UPDATE CAMPAIGN_MST SET
    CAMP_NM = #{camp_nm}, SURV_GB = #{surv_gb}, ACTDATE = #{actdate}, REMARK = #{remark},
    STATUS = #{status}, START_MENT = #{start_ment}, END_MENT = #{end_ment}, UPDTIME = GETDATE(), UPDEMP = #{updemp}
WHERE CMPYCD = #{cmpycd} AND CAMP_NO = #{camp_no}

