mapper.select:
SELECT A.CALL_SEQ, A.CMPYCD, A.CAMP_NO, A.SURV_GB, A.CUST_NM, A.EMAIL, A.TEL_NO, A.STATUS,
ISNULL(A.RSLT_CD,'') AS RSLT_CD, ISNULL(B.CODENM,'미처리') AS RSLT_NM, A.USERID, A.EXT_DATA
FROM CAMPAIGN_CALL_LIST A LEFT OUTER JOIN HABA900T_TBL B ON B.CDTYPE = '920' AND A.RSLT_CD = B.CODECD
WHERE A.CMPYCD = #{CMPYCD} AND A.CAMP_NO = #{CAMP_NO}
 AND A.CALL_SEQ = #{CALL_SEQ} 
ORDER BY A.CALL_SEQ DESC

